TriggerOraclev10g.body:
DECLARE
  PRAGMA AUTONOMOUS_TRANSACTION;
  v_action VARCHAR2(50);
  v_mahd NUMBER;
  v_tongtien NUMBER;
BEGIN
  IF DELETING THEN
    v_action := 'DELETE';
    v_mahd := :OLD.MAHD;
    v_tongtien := :OLD.TONGTIEN;
  ELSIF UPDATING THEN
    v_action := 'UPDATE';
    v_mahd := :NEW.MAHD;
    v_tongtien := :NEW.TONGTIEN;
  ELSE
    v_action := 'INSERT';
    v_mahd := :NEW.MAHD;
    v_tongtien := :NEW.TONGTIEN;
  END IF;

  IF v_tongtien > 1000000 THEN
    pkg_audit.log_fga('HOADON', 'fga_hoadon_tongtien',
      v_action || ' hĂ³a Ä‘Æ¡n giĂ¡ trá»‹ cao: HD' || v_mahd || ' (Tiá»�n: ' || v_tongtien || ')');
  END IF;
EXCEPTION
  WHEN OTHERS THEN NULL;
END;
